def permutations(s):
    result = []
    used = [False] * len(s)

    def backtrack(path):
        if len(path) == len(s):
            result.append(path)
            return

        for i in range(len(s)):
            if used[i]:
                continue

            used[i] = True
            backtrack(path + s[i])
            used[i] = False

    backtrack("")
    return result

print(permutations("abc"))

def generate_parentheses(n):
    result = []

    def backtrack(path, open_count, close_count):
        if len(path) == 2 * n:
            result.append(path)
            return

        if open_count < n:
            backtrack(path + "(", open_count + 1, close_count)

        if close_count < open_count:
            backtrack(path + ")", open_count, close_count + 1)

    backtrack("", 0, 0)
    return result

print(generate_parentheses(3))

def maze_paths(rows, cols):
    result = []

    def backtrack(r, c, path):
        if r == rows - 1 and c == cols - 1:
            result.append(path)
            return

        if c + 1 < cols:
            backtrack(r, c + 1, path + "R")

        if r + 1 < rows:
            backtrack(r + 1, c, path + "D")

    backtrack(0, 0, "")
    return result

print(maze_paths(2, 3))

def combination_sum(candidates, target):
    result = []

    def backtrack(start, path, total):
        if total == target:
            result.append(path[:])
            return

        if total > target:
            return

        for i in range(start, len(candidates)):
            path.append(candidates[i])
            backtrack(i, path, total + candidates[i])
            path.pop()

    backtrack(0, [], 0)
    return result

print(combination_sum([2, 3, 6, 7], 7))

def exist(board, word):
    rows = len(board)
    cols = len(board[0])

    def backtrack(r, c, index):
        if index == len(word):
            return True

        if r < 0 or r >= rows or c < 0 or c >= cols:
            return False

        if board[r][c] != word[index]:
            return False

        temp = board[r][c]
        board[r][c] = "#"

        found = (
            backtrack(r + 1, c, index + 1) or
            backtrack(r - 1, c, index + 1) or
            backtrack(r, c + 1, index + 1) or
            backtrack(r, c - 1, index + 1)
        )

        board[r][c] = temp
        return found

    for r in range(rows):
        for c in range(cols):
            if backtrack(r, c, 0):
                return True

    return False

