def solve_sudoku(board):
    def is_safe(row, col, digit):
        for i in range(9):
            if board[row][i] == digit:
                return False
            if board[i][col] == digit:
                return False

        box_row = (row // 3) * 3
        box_col = (col // 3) * 3

        for r in range(box_row, box_row + 3):
            for c in range(box_col, box_col + 3):
                if board[r][c] == digit:
                    return False

        return True

    def backtrack():
        for row in range(9):
            for col in range(9):
                if board[row][col] == ".":
                    for digit in "123456789":
                        if is_safe(row, col, digit):
                            board[row][col] = digit

                            if backtrack():
                                return True

                            board[row][col] = "."

                    return False

        return True

    backtrack()
    return board

